<?php
namespace App\Console\Commands;
use App\Domain\Characters\CharacterStatsCalculator;use App\Domain\Combat\CombatSimulator;use App\Domain\Combat\Factories\CharacterCombatantFactory;use App\Domain\Combat\Factories\MonsterCombatantFactory;use App\Models\Character;use App\Models\Monster;use Illuminate\Console\Command;
class SimulateCombatCommand extends Command {protected $signature='game:combat:simulate {characterId} {monsterCode}';protected $description='Simulate a non-persistent combat';public function handle(CharacterStatsCalculator $calc,CharacterCombatantFactory $cf,MonsterCombatantFactory $mf,CombatSimulator $sim){if(app()->environment('production')){$this->error('Unavailable in production.');return 1;}$c=Character::find($this->argument('characterId'));$m=Monster::where('code',$this->argument('monsterCode'))->where('status','active')->first();if(!$c||!$m){$this->error('Character or active monster not found.');return 1;}$r=$sim->simulate($cf->make($c,$calc->calculate($c)),$mf->make($m));$this->line("Character: {$c->name}\nMonster: {$m->name}\nResult: {$r->status()}\nRounds: {$r->roundsCount()}\nHealth: {$r->characterInitialHealth()} -> {$r->characterFinalHealth()} | {$r->monsterInitialHealth()} -> {$r->monsterFinalHealth()}");foreach($r->rounds() as $round)foreach($round->actions() as $a)$this->line("R{$a->roundNumber()} {$a->attackerIdentifier()} hit=".($a->hit()?'yes':'no')." critical=".($a->critical()?'yes':'no')." damage={$a->damage()}");return 0;}}
